using System.Collections; using System.Collections.Generic; using UnityEngine; using UnityEngine.EventSystems;  public class ItemSlot : MonoBehaviour, IDropHandler {     public LevelManager levelManager;     public TipoPeca tipoPeca;      [Header("Rejeicao")]     public float rejeicaoDuracao = 0.5f;      [Header("Grid de Comidas")]     public float gridSpacing = 120f;      private List<DragDrop> pecasNoSlot = new List<DragDrop>();      public void OnDrop(PointerEventData eventData)     {         if (eventData.pointerDrag == null) return;          var peca = eventData.pointerDrag.GetComponent<DragDrop>();         if (peca == null) return;          if (eventData.pointerDrag.tag != gameObject.tag)         {             RejeitarPeca(peca);             return;         }          if (peca.tipoPeca != tipoPeca)         {             RejeitarPeca(peca);             return;         }          switch (tipoPeca)         {             case TipoPeca.Numero:                 if (pecasNoSlot.Count > 0)                 {                     RejeitarPeca(peca);                     break;                 }                 EncaixarPeca(peca);                 break;              case TipoPeca.Comida:                 TentarAdicionarComida(peca);                 break;         }     }      private void TentarAdicionarComida(DragDrop peca)     {         if (pecasNoSlot.Count > 0 && pecasNoSlot[0].valorComida != peca.valorComida)         {             ExpulsarTodasPecas();             RejeitarPeca(peca);             return;         }          EncaixarPeca(peca);     }      private void EncaixarPeca(DragDrop peca)     {         // Avisa o DragDrop que a peca foi aceita — OnEndDrag nao vai chamar VoltarParaOrigem.         peca.MarcarAceitoNoSlot();          int randomDrop = Random.Range(0, 6);         SoundManager.Instance?.Play(randomDrop < 3 ? "Drop_1" : "Drop_2");          pecasNoSlot.Add(peca);         peca.GetComponent<CanvasGroup>().blocksRaycasts = false;          RectTransform slotRT = GetComponent<RectTransform>();         RectTransform pecaRT = peca.GetComponent<RectTransform>();          // worldPositionStays: false — nao tenta preservar posicao de mundo.         // Evita que anchoredPosition herde coordenadas gigantes do canvas raiz.         pecaRT.SetParent(slotRT, false);         pecaRT.anchoredPosition = Vector2.zero;          if (tipoPeca == TipoPeca.Numero)         {             // numero fica centrado no slot, posicao ja correta         }         else         {             OrganizarGrid();         }     }      public bool EstaCompleto()     {         if (tipoPeca == TipoPeca.Numero)             return pecasNoSlot.Count == 1;         else             return pecasNoSlot.Count == levelManager.number;     }      public void LimparSlot()     {         foreach (var p in pecasNoSlot)             if (p != null) Destroy(p.gameObject);         pecasNoSlot.Clear();     }      private void OrganizarGrid()     {         int colunas = 3;          for (int i = 0; i < pecasNoSlot.Count; i++)         {             int col = i % colunas;             int row = i / colunas;              int totalColunas = Mathf.Min(pecasNoSlot.Count, colunas);             int totalLinhas = Mathf.CeilToInt(pecasNoSlot.Count / (float)colunas);              float offsetX = (totalColunas - 1) * gridSpacing / 2f;             float offsetY = (totalLinhas - 1) * gridSpacing / 2f;              Vector2 posAlvo = new Vector2(                 col * gridSpacing - offsetX,                 -(row * gridSpacing - offsetY)             );              StartCoroutine(MoverParaPosicao(pecasNoSlot[i].GetComponent<RectTransform>(), posAlvo, 0.2f));         }     }      private IEnumerator MoverParaPosicao(RectTransform rt, Vector2 destino, float duracao)     {         if (rt == null) yield break;          Vector2 origem = rt.anchoredPosition;         float tempo = 0f;          while (tempo < duracao)         {             if (rt == null) yield break;             tempo += Time.deltaTime;             float t = tempo / duracao;             t = t * t * (3f - 2f * t);             rt.anchoredPosition = Vector2.Lerp(origem, destino, t);             yield return null;         }          if (rt != null)             rt.anchoredPosition = destino;     }      private void RejeitarPeca(DragDrop peca)     {         SoundManager.Instance?.Play("Erro");          // Avisa o DragDrop que o drop ja foi tratado (rejeitado).         // OnEndDrag nao vai chamar VoltarParaOrigem de novo.         peca.MarcarTratadoNoDrop();          // VoltarParaOrigem cuida do SetParent (para parentOriginal = containerPecas)         // e da pausa/retomada de fisica. Nao fazemos SetParent aqui.         peca.VoltarParaOrigem(rejeicaoDuracao, this);     }      public void ExpulsarTodasPecas()     {         foreach (var p in pecasNoSlot)         {             if (p == null) continue;             // VoltarParaOrigem cuida do SetParent correto.             p.VoltarParaOrigem(rejeicaoDuracao, this);         }         pecasNoSlot.Clear();     }      // Chamado pelo DragDrop quando o jogador comeca a arrastar uma peca do slot.     public void RemoverDoSlot(DragDrop peca)     {         if (pecasNoSlot.Remove(peca))         {             peca.GetComponent<CanvasGroup>().blocksRaycasts = true;              // Reparenta para containerPecas (nao para o canvas raiz).             // Assim, OnBeginDrag captura parentOriginal = containerPecas corretamente.             peca.transform.SetParent(levelManager.PecasParent, true);              OrganizarGrid();         }     } }